import { useState, useEffect, useCallback } from 'react';
import { Alert } from 'keep-react';

export interface Toast {
  id: string;
  type: 'success' | 'error' | 'info' | 'warning';
  title: string;
  message?: string;
  duration?: number;
  action?: {
    label: string;
    onClick: () => void;
  };
}

interface ToastProps {
  toast: Toast;
  onClose: (id: string) => void;
}

function ToastComponent({ toast, onClose }: ToastProps) {
  const [isVisible, setIsVisible] = useState(false);
  const [isExiting, setIsExiting] = useState(false);

  const handleClose = useCallback(() => {
    setIsExiting(true);
    setTimeout(() => onClose(toast.id), 200);
  }, [toast.id, onClose]);

  useEffect(() => {
    // Animate in
    const timer = setTimeout(() => setIsVisible(true), 50);
    return () => clearTimeout(timer);
  }, []);

  useEffect(() => {
    if (toast.duration && toast.duration > 0) {
      const timer = setTimeout(() => handleClose(), toast.duration);
      return () => clearTimeout(timer);
    }
  }, [toast.duration, handleClose]);

  const getKeepColor = () => {
    switch (toast.type) {
      case 'success':
        return 'success';
      case 'error':
        return 'error';
      case 'warning':
        return 'warning';
      case 'info':
        return 'primary';
      default:
        return 'primary';
    }
  };

  return (
    <div
      className={`
        relative overflow-hidden max-w-md w-full
        transition-all duration-200 ease-out transform
        ${isVisible && !isExiting
          ? 'translate-x-0 opacity-100 scale-100'
          : isExiting
            ? 'translate-x-full opacity-0 scale-95'
            : 'translate-x-full opacity-0 scale-95'
        }
      `}
    >
      <Alert
        color={getKeepColor()}
        withBg
        className="shadow-lg backdrop-blur-sm relative"
      >
        <div className="flex items-start justify-between">
          <div className="flex-1 min-w-0">
            <h3 className="text-sm font-medium">
              {toast.title}
            </h3>
            {toast.message && (
              <p className="mt-1 text-sm opacity-90">
                {toast.message}
              </p>
            )}
            {toast.action && (
              <div className="mt-3">
                <button
                  onClick={toast.action.onClick}
                  className="text-sm font-medium underline hover:no-underline transition-all"
                >
                  {toast.action.label}
                </button>
              </div>
            )}
          </div>
          <button
            onClick={handleClose}
            className="ml-4 text-xl leading-none hover:opacity-70 transition-opacity"
          >
            ├ù
          </button>
        </div>

        {/* Progress bar for duration */}
        {toast.duration && toast.duration > 0 && (
          <div className="absolute bottom-0 left-0 right-0 h-1 bg-black/10">
            <div
              className="h-full bg-current opacity-30 transition-all ease-linear"
              style={{
                animation: `shrink ${toast.duration}ms linear forwards`,
                width: '100%'
              }}
            />
          </div>
        )}
      </Alert>

      <style dangerouslySetInnerHTML={{
        __html: `
          @keyframes shrink {
            from { width: 100%; }
            to { width: 0%; }
          }
        `
      }} />
    </div>
  );
}

export default function ToastContainer() {
  const [toasts, setToasts] = useState<Toast[]>([]);

  const addToast = (toast: Omit<Toast, 'id'>) => {
    const id = Math.random().toString(36).substr(2, 9);
    const newToast: Toast = {
      ...toast,
      id,
      duration: toast.duration ?? 5000,
    };
    setToasts(prev => [...prev, newToast]);
  };

  const removeToast = (id: string) => {
    setToasts(prev => prev.filter(toast => toast.id !== id));
  };


  declare global {
    interface Window {
      toast: {
        success: (title: string, message?: string, options?: Partial<Toast>) => void;
        error: (title: string, message?: string, options?: Partial<Toast>) => void;
        info: (title: string, message?: string, options?: Partial<Toast>) => void;
        warning: (title: string, message?: string, options?: Partial<Toast>) => void;
      };
    }
  }

  // Global toast function
  useEffect(() => {
    window.toast = {
      success: (title: string, message?: string, options?: Partial<Toast>) =>
        addToast({ type: 'success', title, message, ...options }),
      error: (title: string, message?: string, options?: Partial<Toast>) =>
        addToast({ type: 'error', title, message, ...options }),
      info: (title: string, message?: string, options?: Partial<Toast>) =>
        addToast({ type: 'info', title, message, ...options }),
      warning: (title: string, message?: string, options?: Partial<Toast>) =>
        addToast({ type: 'warning', title, message, ...options }),
    };
  }, []);

  return (
    <div className="fixed top-4 right-4 z-[100] space-y-4 pointer-events-none">
      <div className="space-y-3">
        {toasts.map(toast => (
          <div key={toast.id} className="pointer-events-auto">
            <ToastComponent toast={toast} onClose={removeToast} />
          </div>
        ))}
      </div>
    </div>
  );
}

import React, { useState, useEffect, createContext } from 'react';
import { supabase } from '@/react-app/lib/supabase';
import { useAnalytics } from '@/react-app/hooks/useAnalytics';

import { Discount, DiscountContextType } from './DiscountTypes';

// Types are imported for internal use, but not re-exported to avoid HMR issues.
// Import types directly from './DiscountTypes'.

const DiscountContext = createContext<DiscountContextType | undefined>(undefined);

export function DiscountProvider({ children }: { children: React.ReactNode }) {
  const [selectedDiscount, setSelectedDiscount] = useState<Discount | null>(null);
  const [availableDiscounts, setAvailableDiscounts] = useState<Discount[]>([]);
  const [isLoading, setIsLoading] = useState(true);
  const { logEvent } = useAnalytics();

  // Load discounts from Supabase
  useEffect(() => {
    const fetchDiscounts = async () => {
      try {
        const { data, error } = await supabase
          .from('discounts')
          .select('*')
          .eq('is_active', true);

        if (error) throw error;

        if (data) {
          const mappedDiscounts: Discount[] = data.map(d => ({
            id: d.id,
            name: d.name,
            percentage: d.percentage,
            code: d.code,
            description: d.description || undefined,
            isActive: d.is_active || false
          }));
          setAvailableDiscounts(mappedDiscounts);

          // Check for saved discount
          const savedDiscountCode = localStorage.getItem('eka-applied-discount');
          if (savedDiscountCode) {
            const discount = mappedDiscounts.find(d => d.code === savedDiscountCode);
            if (discount) {
              setSelectedDiscount(discount);
            } else {
              localStorage.removeItem('eka-applied-discount');
            }
          }
        } else {
          // Fallback discounts if Supabase returns no data
          const fallbackDiscounts: Discount[] = [
            { id: '1', name: 'Amic Mykola', percentage: 20, code: 'MYKOLA20', description: 'Descompte especial del 20% per a amics de Mykola', isActive: true },
            { id: '2', name: 'Conegut Mykola', percentage: 10, code: 'MYKOLA10', description: 'Descompte del 10% per a coneguts de Mykola', isActive: true },
            { id: '3', name: 'Benvinguda', percentage: 20, code: 'WELCOME20', description: 'Descompte de benvinguda', isActive: true }
          ];
          setAvailableDiscounts(fallbackDiscounts);
        }
      } catch (error) {
        console.error('Error fetching discounts:', error);
        // Fallback discounts on error
        const fallbackDiscounts: Discount[] = [
          { id: '1', name: 'Amic Mykola', percentage: 20, code: 'MYKOLA20', description: 'Descompte especial del 20% per a amics de Mykola', isActive: true },
          { id: '2', name: 'Conegut Mykola', percentage: 10, code: 'MYKOLA10', description: 'Descompte del 10% per a coneguts de Mykola', isActive: true },
          { id: '3', name: 'Benvinguda', percentage: 20, code: 'WELCOME20', description: 'Descompte de benvinguda', isActive: true }
        ];
        setAvailableDiscounts(fallbackDiscounts);
      } finally {
        setIsLoading(false);
      }
    };

    fetchDiscounts();
  }, []);

  const applyDiscount = async (code: string): Promise<boolean> => {
    const discount = availableDiscounts.find(
      d => d.code.toLowerCase() === code.toLowerCase()
    );

    if (discount) {
      setSelectedDiscount(discount);
      localStorage.setItem('eka-applied-discount', discount.code);

      // Log the interaction
      logEvent('apply_discount', {
        discount_id: discount.id,
        discount_name: discount.name,
        percentage: discount.percentage,
        success: true
      }, code);

      return true;
    }

    // Log failed attempt
    logEvent('apply_discount_failed', {
      success: false,
      reason: 'Invalid code'
    }, code);

    return false;
  };

  const removeDiscount = () => {
    setSelectedDiscount(null);
    localStorage.removeItem('eka-applied-discount');
  };

  const calculateDiscountedPrice = (originalPrice: number): number => {
    if (!selectedDiscount) return originalPrice;
    const discountAmount = (originalPrice * selectedDiscount.percentage) / 100;
    return Math.round((originalPrice - discountAmount) * 100) / 100;
  };

  const getDiscountAmount = (originalPrice: number): number => {
    if (!selectedDiscount) return 0;
    return Math.round((originalPrice * selectedDiscount.percentage) / 100 * 100) / 100;
  };

  return (
    <DiscountContext.Provider value={{
      selectedDiscount,
      availableDiscounts,
      applyDiscount,
      removeDiscount,
      calculateDiscountedPrice,
      getDiscountAmount,
      isLoading
    }}>
      {children}
    </DiscountContext.Provider>
  );
}


export const useDiscount = () => {
  const context = React.useContext(DiscountContext);
  if (context === undefined) {
    throw new Error('useDiscount must be used within a DiscountProvider');
  }
  return context;
};

import React, { useEffect, useState, createContext } from 'react';
import { User, Session } from '@supabase/supabase-js';
import { supabase } from '../lib/supabase';

export interface AuthContextType {
  user: User | null;
  session: Session | null;
  loading: boolean;
  signInWithGoogle: () => Promise<void>;
  signOut: () => Promise<void>;
}

const AuthContext = createContext<AuthContextType | undefined>(undefined);

export function SupabaseAuthProvider({ children }: { children: React.ReactNode }) {
  const [user, setUser] = useState<User | null>(null);
  const [session, setSession] = useState<Session | null>(null);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    // Check active sessions and sets the user
    supabase.auth.getSession().then(({ data: { session } }) => {
      setSession(session);
      setUser(session?.user ?? null);
      setLoading(false);
    });

    // Listen for changes on auth state (sign in, sign out, etc.)
    const { data: { subscription } } = supabase.auth.onAuthStateChange((_event, session) => {
      setSession(session);
      setUser(session?.user ?? null);
      setLoading(false);
    });

    return () => subscription.unsubscribe();
  }, []);

  const signInWithGoogle = async () => {
    await supabase.auth.signInWithOAuth({
      provider: 'google',
      options: {
        redirectTo: window.location.origin,
      },
    });
  };

  const signOut = async () => {
    await supabase.auth.signOut();
  };

  return (
    <AuthContext.Provider value={{ user, session, loading, signInWithGoogle, signOut }}>
      {children}
    </AuthContext.Provider>
  );
}


export function useSupabaseAuth() {
  const context = React.useContext(AuthContext);
  if (context === undefined) {
    throw new Error('useSupabaseAuth must be used within a SupabaseAuthProvider');
  }
  return context;
}
